class Solution(object):
    def numberOfSubstrings(self, s):
        n = len(s)
        # zeros in subarray <= sqrt(ones) => zeros <= ~sqrt(n)
        # For each left l, find minimum right r where subarray is dominant
        # Then all extensions to the right are also valid
        # Key: zeros count <= sqrt(n) ~= 200 for n=40000
        # For each l, iterate right adding chars; stop when zeros^2 > ones
        ans = 0
        for l in range(n):
            ones = 0
            zeros = 0
            for r in range(l, n):
                if s[r] == '1':
                    ones += 1
                else:
                    zeros += 1
                if ones >= zeros * zeros:
                    ans += 1
                elif zeros * zeros > ones + (n - r - 1):
                    # Even adding all remaining ones won't help
                    break
        return ans
